/**
 * ExecuteAction
 */
async function executeAction(actionId) {
    // Zachytit tlačítko PŘED jakýmkoliv await
    const btn = event.target;
    const originalText = btn.textContent;

    const csrfToken = await getCSRFToken();

    if (!csrfToken || typeof csrfToken !== 'string' || csrfToken.length === 0) {
        wgsToast.error('CSRF token nebyl nalezen nebo je neplatný. Obnovte stránku.');
        return;
    }

    const potvrdit = await wgsConfirm('Spustit tuto akci? Bude provedena automaticky.', {
        titulek: 'Spustit akci',
        btnPotvrdit: 'Spustit'
    });
    if (!potvrdit) return;

    btn.disabled = true;
    btn.textContent = 'Provádění...';

    const payload = {
        action_id: actionId,
        csrf_token: csrfToken
    };

    fetch('api/admin.php?action=execute_action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
    })
    .then(async r => {
        let responseData;
        try {
            responseData = await r.json();
        } catch (e) {
            responseData = null;
        }

        if (!r.ok) {
            let errorMsg = `HTTP ${r.status}`;
            if (responseData) {
                errorMsg = responseData.message || 'Neznámá chyba';
                if (responseData.debug) {
                    errorMsg += '\n\n' + Object.entries(responseData.debug)
                        .map(([k, v]) => `${k}: ${typeof v === 'object' ? JSON.stringify(v, null, 2) : v}`)
                        .join('\n');
                }
            }
            throw new Error(errorMsg);
        }

        return responseData;
    })
    .then(data => {
        if (isSuccess(data)) {
            const execTime = data.execution_time || 'neznámý čas';
            wgsToast.success(`Akce dokončena: ${data.message} (${execTime})`);
            loadActionsModal();
        } else {
            wgsToast.error('Chyba: ' + (data.error || data.message || 'Neznámá chyba'));
            btn.disabled = false;
            btn.textContent = originalText;
        }
    })
    .catch(err => {
        wgsToast.error('Chyba při provádění akce: ' + err.message);
        btn.disabled = false;
        btn.textContent = originalText;
    });
}

